module RefModule(
    input clk,
    input reset,
    input data_in,
    input shift_en,
    output reg data_out
);reg [7:0] obf_shift_reg;

    always @(posedge clk) begin
        if (reset) begin
            obf_shift_reg <= 8'b0;
        end else if (shift_en) begin
            obf_shift_reg <= {obf_shift_reg[6:0], data_in};
        end
    end

    assign data_out = obf_shift_reg[7];

endmodule
